CREATE OR REPLACE FUNCTION fpa_dep_int_month (as_depno char , adt_date timestamp(0) , as_dep_type char , as_item_type char ) RETURNS bigint AS $body$
DECLARE

ldc_int bigint;

BEGIN
  select  sc_dep_m_creditor_item.deposit_balance into STRICT ldc_int
  from    sc_dep_m_creditor
       ,  sc_dep_m_creditor_item
  where (sc_dep_m_creditor_item.item_type = as_item_type )
  and (sc_dep_m_creditor.deposit_account_no = as_depno)
  and (sc_dep_m_creditor.deposit_type_code = as_dep_type)
  and (sc_dep_m_creditor_item.operate_date = adt_date)
  and (sc_dep_m_creditor_item.deposit_account_no = sc_dep_m_creditor.deposit_account_no)
;
  return ldc_int;
  exception
    when no_data_found then  ldc_int := 0;return ldc_int;
    when others then CALL spa_dberror('FPA_DEP_INT_MONTH');

END;
